<?php
namespace Zclone\Core;
final class Security { public static function e(string $v): string { return htmlspecialchars($v, ENT_QUOTES|ENT_SUBSTITUTE, 'UTF-8'); } public static function csrf(): string { if (empty($_SESSION['_csrf'])) $_SESSION['_csrf']=bin2hex(random_bytes(32)); return $_SESSION['_csrf']; } public static function verifyCsrf(?string $t): bool { return is_string($t) && hash_equals($_SESSION['_csrf'] ?? '', $t); } public static function jwt(array $payload,int $ttl=3600): string { $payload['exp']=time()+$ttl; $h=self::b64(json_encode(['alg'=>'HS256','typ'=>'JWT'])); $p=self::b64(json_encode($payload)); $s=self::b64(hash_hmac('sha256', "$h.$p", Env::get('JWT_SECRET','secret'), true)); return "$h.$p.$s"; } private static function b64(string $v): string { return rtrim(strtr(base64_encode($v), '+/', '-_'), '='); } }
